// Script: generar_13_logo_chiqui.js
// Que hace: coloca los dos logos oficiales de CHIQUI (ya editados para
// quitarles el fondo blanco y volverlo transparente) en la carpeta public/
// del proyecto, donde Next.js sirve archivos estaticos como imagenes.
//
//   1) public/logo-chiqui-completo.png -- el logo grande con "Entre Senales"
//      y el eslogan. Se usara en login y registro.
//   2) public/logo-chiqui-compacto.png -- el logo chico, solo el perrito y
//      "CHIQUI" sin subtitulo. Se usara en el header de las 6 pantallas
//      internas (dashboard, calendario, registro diario, prevencion,
//      analisis, perfil).
//
// Este script SOLO coloca las imagenes. El siguiente script actualizara
// el codigo de cada pantalla para mostrarlas.
//
// Como correrlo: node generar_13_logo_chiqui.js
// Confirma "OK" para ambos archivos

const fs = require('fs');
const path = require('path');

function escribirImagen(relPath, b64) {
  const filePath = path.join(...relPath.split('/'));
  const buffer = Buffer.from(b64, 'base64');
  const dir = path.dirname(filePath);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(filePath, buffer);
  console.log('OK: ' + filePath + ' (' + (buffer.length / 1024).toFixed(1) + ' KB)');
}

escribirImagen('public/logo-chiqui-completo.png', "");
escribirImagen('public/logo-chiqui-compacto.png', "");
